apiContract:
{
  "GET /api/governance/guardrails": {
    "description": "List all guardrail configs with optional filtering by scope",
    "queryParams": {
      "scope": "string (optional) - filter by scope: global, virtual_key, team, customer",
      "scope_id": "string (optional) - filter by scope target ID",
      "limit": "number (optional, default 50)",
      "offset": "number (optional, default 0)"
    },
    "response": {
      "guardrails": [
        {
          "id": "uuid string",
          "name": "string - display name for this guardrail config",
          "enabled": "boolean",
          "scope": "string - global|virtual_key|team|customer",
          "scope_id": "string or null - the target ID when scope is non-global",
          "scope_name": "string (API-only, resolved for UI) - human-readable scope target name",
          "guardrails": [
            {
              "id": "uuid string",
              "type": "string - Contains|RegexMatch|WordCount|CharacterCount|SentenceCount|EndsWith|AllLowercase|AllUppercase|NotNull|ContainsCode|ValidURLs|ValidJSON|JSONKeys|ModelWhitelist|AllowedRequestTypes",
              "enabled": "boolean",
              "params": "object - polymorphic guardrail-specific config"
            }
          ],
          "created_at": "RFC3339 timestamp",
          "updated_at": "RFC3339 timestamp"
        }
      ],
      "total": "number",
      "offset": "number"
    }
  },
  "POST /api/governance/guardrails": {
    "description": "Create a new guardrail config",
    "body": {
      "name": "string (required)",
      "enabled": "boolean (default true)",
      "scope": "string (default global) - global|virtual_key|team|customer",
      "scope_id": "string (required if scope != global)",
      "guardrails": [
        {
          "type": "string (required) - guardrail type identifier",
          "enabled": "boolean (default true)",
          "params": "object - guardrail-specific parameters as JSON"
        }
      ]
    },
    "response": {
      "message": "string",
      "guardrail_config": "full TableGuardrailConfig response object"
    }
  },
  "GET /api/governance/guardrails/{id}": {
    "description": "Get a single guardrail config by ID",
    "response": {
      "guardrail_config": "full TableGuardrailConfig object"
    }
  },
  "PUT /api/governance/guardrails/{id}": {
    "description": "Update an existing guardrail config",
    "body": {
      "name": "string (optional)",
      "enabled": "boolean (optional)",
      "guardrails": "array of guardrail objects (optional) - replaces existing list if provided"
    },
    "response": {
      "message": "string",
      "guardrail_config": "updated full TableGuardrailConfig object"
    }
  },
  "DELETE /api/governance/guardrails/{id}": {
    "description": "Delete a guardrail config",
    "response": {
      "message": "string"
    }
  }
}
